import streamlit as st
from openpyxl import Workbook
from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
from openpyxl.drawing.image import Image as XLImage
from openpyxl.utils import get_column_letter
import datetime, io, base64, tempfile, os

# ══════════════════════════════════════════════════════════════════════════════
#  EMBEDDED COMPANY LOGO  (base64 – no external file needed)
# ══════════════════════════════════════════════════════════════════════════════
# fmt: off

DSS_LOGO_B64 = ""

# fmt: on

# ══════════════════════════════════════════════════════════════════════════════
#  COLORS
# ══════════════════════════════════════════════════════════════════════════════
NAVY        = "0D2137"
NAVY_MID    = "1B3A5C"
ORANGE      = "E8722A"
ORANGE_SOFT = "F4A261"
CREAM       = "FDF6EE"
WHITE       = "FFFFFF"
LIGHT_BLUE  = "EBF2FA"
SILVER      = "D6DDE6"
DARK_TEXT   = "1A1A2E"
MID_TEXT    = "4A5568"

# ══════════════════════════════════════════════════════════════════════════════
#  HELPER STYLING FUNCTIONS
# ══════════════════════════════════════════════════════════════════════════════
def _side(color, style="thin"):
    return Side(style=style, color=color)

def thin(c=SILVER):
    s = _side(c)
    return Border(left=s, right=s, top=s, bottom=s)

def medium(c=NAVY_MID):
    s = _side(c, "medium")
    return Border(left=s, right=s, top=s, bottom=s)

def cs(ws, row, col, value=None, bold=False, size=10, color=DARK_TEXT,
       bg=None, ha="left", va="center", wrap=False, num_fmt=None,
       border=None, italic=False, indent=0):
    c = ws.cell(row=row, column=col)
    if value is not None:
        c.value = value
    c.font = Font(name="Arial", size=size, bold=bold, color=color, italic=italic)
    c.alignment = Alignment(horizontal=ha, vertical=va, wrap_text=wrap, indent=indent)
    if bg:
        c.fill = PatternFill("solid", start_color=bg, end_color=bg)
    if num_fmt:
        c.number_format = num_fmt
    if border:
        c.border = border
    return c

def fill_range(ws, row, c1, c2, bg):
    for col in range(c1, c2+1):
        ws.cell(row=row, column=col).fill = PatternFill("solid", start_color=bg, end_color=bg)

def border_range(ws, row, c1, c2, border):
    for col in range(c1, c2+1):
        ws.cell(row=row, column=col).border = border

def mg(ws, r1, c1, r2, c2):
    ws.merge_cells(start_row=r1, start_column=c1, end_row=r2, end_column=c2)

# ══════════════════════════════════════════════════════════════════════════════
#  WEIGHT / DIMENSION CALCULATIONS
# ══════════════════════════════════════════════════════════════════════════════
def weight(length, width, thickness):
    return (length * width * thickness * 7.85) / 1_000_000

def upright_sheet_size(w, d):       return w + d + w + 15
def pipe_beam_sheet_size(h, w):     return 2 * (h + w)
def roll_beam_sheet_size(h, w):     return (4*h + 2*w) + 20
def deep_bar_size(depth):           return depth - 65
def cross_length(d, gap, ud):       return ((d - 50)**2 + gap**2)**0.5 + 50

def calc_rack_weight(rack):
    uwid  = upright_sheet_size(rack["uw"], rack["ud"])
    u_wt  = weight(rack["ul"], uwid, rack["ut"])
    bwid  = (pipe_beam_sheet_size(rack["bh"], rack["bw"])
             if rack["bt"] == "Pipe Beam"
             else roll_beam_sheet_size(rack["bh"], rack["bw"]))
    b_wt  = weight(rack["bl"], bwid, rack["bth"])
    d_len = deep_bar_size(rack["depth"])
    d_wt  = weight(d_len, 92, rack["dth"])
    c_len = cross_length(d_len, rack["gap"], rack["ud"])
    c_wt  = weight(c_len, 92, rack["cth"])
    return (u_wt * 4) + (b_wt * 2 * rack["levels"]) + (d_wt * 4) + (c_wt * 2)

# ══════════════════════════════════════════════════════════════════════════════
#  EXCEL BUILDER
# ══════════════════════════════════════════════════════════════════════════════
def build_excel(client, product, offer_no, date_obj, project_name,
                rack_data, rate_per_kg, out_path="quotation.xlsx"):

    wb = Workbook()
    ws = wb.active
    ws.title = "Commercial Offer"
    ws.sheet_view.showGridLines = False

    # Column widths  A=1 … H=8
    for col, w in {1:3, 2:6, 3:38, 4:15, 5:10, 6:19, 7:19, 8:3}.items():
        ws.column_dimensions[get_column_letter(col)].width = w

    ws.sheet_format.defaultRowHeight = 18
    R = 1   # row pointer

    # ── Save logo from embedded base64 ───────────────────────────────────────
    logo_tmp = None
    try:
        logo_bytes = base64.b64decode(DSS_LOGO_B64)
        with tempfile.NamedTemporaryFile(delete=False, suffix=".png") as tf:
            tf.write(logo_bytes)
            logo_tmp = tf.name
    except Exception:
        pass

    # ─────────────────────────────────────────────────────────────────────────
    # HEADER
    # ─────────────────────────────────────────────────────────────────────────
    ws.row_dimensions[R].height = 5
    fill_range(ws, R, 1, 8, NAVY); R += 1

    # Logo + company name row
    ws.row_dimensions[R].height = 72
    fill_range(ws, R, 1, 8, NAVY)

    if logo_tmp:
        try:
            img = XLImage(logo_tmp)
            img.width, img.height = 180, 64
            img.anchor = f"B{R}"
            ws.add_image(img)
        except Exception:
            pass

    mg(ws, R, 4, R, 7)
    c = ws.cell(row=R, column=4)
    c.value = "BRIJ INDUSTRIES"
    c.font = Font(name="Arial", size=16, bold=True, color=WHITE)
    c.alignment = Alignment(horizontal="right", vertical="center", indent=1)
    c.fill = PatternFill("solid", start_color=NAVY, end_color=NAVY)
    R += 1

    # Orange sub-brand strip
    ws.row_dimensions[R].height = 18
    fill_range(ws, R, 1, 8, ORANGE)
    mg(ws, R, 2, R, 7)
    cs(ws, R, 2, "Authorised Dealer – DSS Dolphin Storage Solutions | Modular Mezzanine & Racking Systems",
       bold=False, size=9, color=WHITE, bg=ORANGE, ha="center"); R += 1

    # Address strip
    ws.row_dimensions[R].height = 15
    fill_range(ws, R, 1, 8, NAVY_MID)
    mg(ws, R, 2, R, 7)
    cs(ws, R, 2, "86/3/1 Road No 7, Mundka Industrial Area, New Delhi – 110041   |   GST: 07AAMFB6403G1ZM",
       size=8, color="AABBCC", bg=NAVY_MID, ha="center"); R += 1

    # Contact strip
    ws.row_dimensions[R].height = 14
    fill_range(ws, R, 1, 8, NAVY_MID)
    mg(ws, R, 2, R, 7)
    cs(ws, R, 2, "brijindustries09@rediffmail.com   |   www.brijindustries.in   |   +91 9625589161  /  +91 9811096149",
       size=8, color="7799AA", bg=NAVY_MID, ha="center"); R += 1

    # Thin orange rule
    ws.row_dimensions[R].height = 5
    fill_range(ws, R, 1, 8, ORANGE); R += 1

    # Spacer
    ws.row_dimensions[R].height = 8; R += 1

    # ─────────────────────────────────────────────────────────────────────────
    # OFFER DETAILS CARD
    # ─────────────────────────────────────────────────────────────────────────
    ws.row_dimensions[R].height = 22
    mg(ws, R, 2, R, 7)
    c = ws.cell(row=R, column=2)
    c.value = "  COMMERCIAL OFFER"
    c.font = Font(name="Arial", size=12, bold=True, color=WHITE)
    c.alignment = Alignment(horizontal="left", vertical="center")
    c.fill = PatternFill("solid", start_color=NAVY, end_color=NAVY)
    c.border = thin(NAVY)
    R += 1

    def detail_row(lbl_l, val_l, lbl_r, val_r, bg=LIGHT_BLUE):
        nonlocal R
        ws.row_dimensions[R].height = 20
        fill_range(ws, R, 2, 7, bg)
        border_range(ws, R, 2, 7, thin())
        cs(ws, R, 2, lbl_l, bold=True, size=9, color=NAVY_MID, bg=bg, ha="right")
        mg(ws, R, 3, R, 4)
        cs(ws, R, 3, val_l, size=9, color=DARK_TEXT, bg=bg, indent=1)
        cs(ws, R, 5, lbl_r, bold=True, size=9, color=NAVY_MID, bg=bg, ha="right")
        mg(ws, R, 6, R, 7)
        cs(ws, R, 6, val_r, size=9, color=DARK_TEXT, bg=bg, indent=1)
        R += 1

    detail_row("To :",      client,       "Date :",     date_obj.strftime("%d %B %Y"), bg=LIGHT_BLUE)
    detail_row("Product :", product,      "Offer No. :", offer_no,                     bg=WHITE)
    detail_row("Project :", project_name, "",           "",                            bg=LIGHT_BLUE)

    ws.row_dimensions[R].height = 10; R += 1

    # ─────────────────────────────────────────────────────────────────────────
    # SCOPE OF SUPPLY TABLE
    # ─────────────────────────────────────────────────────────────────────────
    ws.row_dimensions[R].height = 22
    mg(ws, R, 2, R, 7)
    c = ws.cell(row=R, column=2)
    c.value = "  SCOPE OF SUPPLY"
    c.font = Font(name="Arial", size=11, bold=True, color=WHITE)
    c.alignment = Alignment(horizontal="left", vertical="center")
    c.fill = PatternFill("solid", start_color=ORANGE, end_color=ORANGE)
    R += 1

    # Table headers
    ws.row_dimensions[R].height = 26
    hdrs = [(2,"SR.","center"),(3,"DESCRIPTION","left"),(4,"TYPE","center"),
            (5,"QTY","center"),(6,"UNIT PRICE (₹)","center"),(7,"AMOUNT (₹)","center")]
    for col, txt, al in hdrs:
        c = ws.cell(row=R, column=col)
        c.value = txt
        c.font = Font(name="Arial", size=9, bold=True, color=WHITE)
        c.fill = PatternFill("solid", start_color=NAVY, end_color=NAVY)
        c.alignment = Alignment(horizontal=al, vertical="center",
                                indent=1 if al=="left" else 0)
        c.border = thin(SILVER)
    R += 1

    total_basic = 0
    sr = 1
    row_bgs = [WHITE, CREAM]

    for rack in rack_data:
        rw         = calc_rack_weight(rack)
        main_price = rw * rate_per_kg
        addon_price= rw * 0.70 * rate_per_kg
        main_total = main_price * rack["main_qty"]
        total_basic += main_total

        bg = row_bgs[sr % 2]
        ws.row_dimensions[R].height = 20
        fill_range(ws, R, 2, 7, bg)
        border_range(ws, R, 2, 7, thin())

        cs(ws, R, 2, sr, size=9, color=MID_TEXT, bg=bg, ha="center")
        cs(ws, R, 3, f"{rack['module']}  –  {rack['name']}",
           bold=True, size=9, color=DARK_TEXT, bg=bg, indent=1)
        cs(ws, R, 4, "Main Rack", size=9, color=NAVY_MID, bg=bg, ha="center")
        cs(ws, R, 5, rack["main_qty"], size=9, color=DARK_TEXT, bg=bg, ha="center")
        cs(ws, R, 6, round(main_price, 2), size=9, bg=bg, ha="right", num_fmt="#,##0.00")
        cs(ws, R, 7, round(main_total, 2), bold=True, size=9,
           color=NAVY_MID, bg=bg, ha="right", num_fmt="#,##0.00")
        R += 1; sr += 1

        if rack["addon_qty"] > 0:
            addon_total  = addon_price * rack["addon_qty"]
            total_basic += addon_total
            bg = row_bgs[sr % 2]
            ws.row_dimensions[R].height = 20
            fill_range(ws, R, 2, 7, bg)
            border_range(ws, R, 2, 7, thin())

            cs(ws, R, 2, sr, size=9, color=MID_TEXT, bg=bg, ha="center")
            cs(ws, R, 3, f"{rack['module']}  –  {rack['name']}",
               size=9, color=MID_TEXT, bg=bg, indent=1)
            cs(ws, R, 4, "Add-on Rack", size=9, color=ORANGE, bg=bg, ha="center")
            cs(ws, R, 5, rack["addon_qty"], size=9, color=DARK_TEXT, bg=bg, ha="center")
            cs(ws, R, 6, round(addon_price,2), size=9, bg=bg, ha="right", num_fmt="#,##0.00")
            cs(ws, R, 7, round(addon_total,2), bold=True, size=9,
               color=NAVY_MID, bg=bg, ha="right", num_fmt="#,##0.00")
            R += 1; sr += 1

    # Subtotal
    ws.row_dimensions[R].height = 22
    mg(ws, R, 2, R, 6)
    c = ws.cell(row=R, column=2)
    c.value = "SUBTOTAL (BASIC AMOUNT)"
    c.font = Font(name="Arial", size=10, bold=True, color=NAVY)
    c.alignment = Alignment(horizontal="right", vertical="center", indent=1)
    c.fill = PatternFill("solid", start_color=LIGHT_BLUE, end_color=LIGHT_BLUE)
    c.border = medium()
    cs(ws, R, 7, round(total_basic,2), bold=True, size=10, color=NAVY,
       bg=LIGHT_BLUE, ha="right", num_fmt="#,##0.00", border=medium())
    R += 1

    ws.row_dimensions[R].height = 10; R += 1

    # ─────────────────────────────────────────────────────────────────────────
    # PRICING SUMMARY
    # ─────────────────────────────────────────────────────────────────────────
    gst_amount  = round(total_basic * 0.18, 2)
    grand_total = round(total_basic + gst_amount, 2)

    def sum_row(lbl, val, bg=WHITE, bold=False, vc=DARK_TEXT, is_text=False):
        nonlocal R
        ws.row_dimensions[R].height = 20
        mg(ws, R, 4, R, 6)
        c_l = ws.cell(row=R, column=4)
        c_l.value = lbl
        c_l.font = Font(name="Arial", size=10, bold=bold, color=MID_TEXT)
        c_l.alignment = Alignment(horizontal="right", vertical="center", indent=1)
        c_l.fill = PatternFill("solid", start_color=bg, end_color=bg)
        c_l.border = thin()
        c_v = ws.cell(row=R, column=7)
        c_v.value = val
        c_v.font = Font(name="Arial", size=10, bold=bold, color=vc, italic=is_text)
        c_v.alignment = Alignment(horizontal="center" if is_text else "right",
                                   vertical="center", indent=1)
        c_v.fill = PatternFill("solid", start_color=bg, end_color=bg)
        c_v.border = thin()
        if not is_text:
            c_v.number_format = "#,##0.00"
        R += 1

    sum_row("Basic Amount",      round(total_basic,2), bg=WHITE, bold=True, vc=NAVY)
    sum_row("Freight Charges",   "Inclusive", bg=CREAM, is_text=True, vc=ORANGE)
    sum_row("Erection Charges",  "Inclusive", bg=CREAM, is_text=True, vc=ORANGE)
    sum_row("GST @ 18%",         gst_amount,  bg=WHITE)

    # Grand Total row
    ws.row_dimensions[R].height = 28
    mg(ws, R, 2, R, 6)
    c_gl = ws.cell(row=R, column=2)
    c_gl.value = "GRAND TOTAL  (Including GST @ 18%)"
    c_gl.font = Font(name="Arial", size=12, bold=True, color=WHITE)
    c_gl.alignment = Alignment(horizontal="right", vertical="center", indent=1)
    c_gl.fill = PatternFill("solid", start_color=ORANGE, end_color=ORANGE)
    c_gl.border = medium(ORANGE)

    c_gv = ws.cell(row=R, column=7)
    c_gv.value = grand_total
    c_gv.font = Font(name="Arial", size=12, bold=True, color=WHITE)
    c_gv.alignment = Alignment(horizontal="right", vertical="center", indent=1)
    c_gv.fill = PatternFill("solid", start_color=NAVY, end_color=NAVY)
    c_gv.border = medium(NAVY)
    c_gv.number_format = '₹ #,##0.00'
    R += 1

    ws.row_dimensions[R].height = 12; R += 1

    # ─────────────────────────────────────────────────────────────────────────
    # TERMS & BANK DETAILS  (two columns)
    # ─────────────────────────────────────────────────────────────────────────
    ws.row_dimensions[R].height = 20
    mg(ws, R, 2, R, 4)
    c = ws.cell(row=R, column=2)
    c.value = "  TERMS & CONDITIONS"
    c.font = Font(name="Arial", size=10, bold=True, color=WHITE)
    c.alignment = Alignment(horizontal="left", vertical="center")
    c.fill = PatternFill("solid", start_color=NAVY_MID, end_color=NAVY_MID)

    mg(ws, R, 5, R, 7)
    c2 = ws.cell(row=R, column=5)
    c2.value = "  BANK DETAILS"
    c2.font = Font(name="Arial", size=10, bold=True, color=WHITE)
    c2.alignment = Alignment(horizontal="left", vertical="center")
    c2.fill = PatternFill("solid", start_color=NAVY_MID, end_color=NAVY_MID)
    R += 1

    terms = [
        "Payment: 50% advance, balance against delivery",
        "Delivery: 10–12 weeks from advance receipt",
        "Warranty: 12 months from commissioning date",
        "GST @ 18% applicable as per Government norms",
        "Prices valid for 30 days from date of offer",
    ]
    bank = [
        "Account Name: BRIJ INDUSTRIES",
        "Bank: HDFC Bank Ltd.",
        "Account No.: 50100512345678",
        "IFSC Code: HDFC0001234",
        "Branch: Mundka, New Delhi",
    ]
    for t, b in zip(terms, bank):
        ws.row_dimensions[R].height = 18
        mg(ws, R, 2, R, 4)
        c = ws.cell(row=R, column=2)
        c.value = f"  • {t}"
        c.font = Font(name="Arial", size=8, color=MID_TEXT)
        c.alignment = Alignment(horizontal="left", vertical="center")
        c.fill = PatternFill("solid", start_color=LIGHT_BLUE, end_color=LIGHT_BLUE)
        c.border = thin()
        mg(ws, R, 5, R, 7)
        c2 = ws.cell(row=R, column=5)
        c2.value = f"  {b}"
        c2.font = Font(name="Arial", size=8, color=MID_TEXT)
        c2.alignment = Alignment(horizontal="left", vertical="center")
        c2.fill = PatternFill("solid", start_color=CREAM, end_color=CREAM)
        c2.border = thin()
        R += 1

    # Signature area
    ws.row_dimensions[R].height = 8; R += 1
    ws.row_dimensions[R].height = 38
    mg(ws, R, 2, R, 4)
    c = ws.cell(row=R, column=2)
    c.value = "Customer Signature & Stamp"
    c.font = Font(name="Arial", size=8, color=SILVER, italic=True)
    c.alignment = Alignment(horizontal="center", vertical="bottom")
    c.border = Border(top=Side(style="medium", color=NAVY_MID))
    mg(ws, R, 5, R, 7)
    c2 = ws.cell(row=R, column=5)
    c2.value = "For BRIJ INDUSTRIES / DSS Dolphin Storage Solutions"
    c2.font = Font(name="Arial", size=8, color=SILVER, italic=True)
    c2.alignment = Alignment(horizontal="center", vertical="bottom")
    c2.border = Border(top=Side(style="medium", color=NAVY_MID))
    R += 1

    # Footer band
    ws.row_dimensions[R].height = 5
    fill_range(ws, R, 1, 8, ORANGE); R += 1
    ws.row_dimensions[R].height = 14
    fill_range(ws, R, 1, 8, NAVY)
    mg(ws, R, 2, R, 7)
    cs(ws, R, 2, "Thank you for considering DSS Dolphin Storage Solutions. We look forward to serving you.",
       size=8, color="7799AA", bg=NAVY, ha="center")

    # Print setup
    ws.page_setup.orientation = "portrait"
    ws.page_setup.paperSize   = 9
    ws.page_setup.fitToPage   = True
    ws.page_setup.fitToWidth  = 1
    ws.print_area = f"A1:{get_column_letter(8)}{R}"

    wb.save(out_path)

    if logo_tmp and os.path.exists(logo_tmp):
        try: os.unlink(logo_tmp)
        except: pass

    return total_basic, gst_amount, grand_total

# ══════════════════════════════════════════════════════════════════════════════
